/**
 * Algorithmic List Framework
 *
 * Defines a registry of named query definitions that power auto-generated
 * lists such as "Trending in Your Circle", "New on Hone", etc.
 *
 * Each query is a pure declarative definition — no I/O. The runtime
 * (a daily refresh job) evaluates queries against repositories and
 * materializes/updates the corresponding shelf.
 *
 * All algorithmic lists are authored with `authorType: "algorithmic"` and
 * carry the label "Generated by Hone".
 */

import type { EntityId } from "./types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/**
 * Supported query types that the refresh job knows how to evaluate.
 */
export type AlgorithmicQueryType =
  | "trending_in_circle"
  | "new_on_hone"
  | "highly_ranked_this_month"
  | "popular_in_top_genre"
  | "mutuals_reading_now";

/**
 * Parameters that scope a query to a specific user context.
 * Not all queries use all fields — e.g., `new_on_hone` is global.
 */
export interface QueryParams {
  /** The viewer/user for whom the list is generated */
  userId?: EntityId;
  /** Time window in days for recency-based queries */
  windowDays?: number;
  /** Maximum items to include in the materialized list */
  maxItems?: number;
  /** Minimum number of events/finishes to qualify */
  minThreshold?: number;
}

/**
 * A single query definition in the registry.
 */
export interface AlgorithmicQueryDefinition {
  /** Unique query type identifier */
  type: AlgorithmicQueryType;
  /** Human-readable title shown to users */
  title: string;
  /** Short description of how the query works */
  description: string;
  /** Default parameters (can be overridden per-user) */
  defaultParams: Required<QueryParams>;
  /** Whether this query is scoped per-user or global */
  scope: "per_user" | "global";
}

/**
 * Result of evaluating an algorithmic query — a list of book IDs
 * in ranked order, ready to be materialized into a shelf.
 */
export interface AlgorithmicQueryResult {
  queryType: AlgorithmicQueryType;
  bookIds: EntityId[];
  generatedAt: Date;
  /** User this was generated for (null for global queries) */
  userId: EntityId | null;
}

/**
 * The author label applied to all algorithmic lists.
 */
export const ALGORITHMIC_AUTHOR_LABEL = "Generated by Hone";

