// ---------------------------------------------------------------------------
// Query Registry
// ---------------------------------------------------------------------------

/**
 * The query registry: an immutable array of all algorithmic query definitions.
 * Used by the refresh job to iterate and evaluate each query.
 */
export const ALGORITHMIC_QUERY_REGISTRY: readonly AlgorithmicQueryDefinition[] = [
  TRENDING_IN_CIRCLE,
  NEW_ON_HONE,
  HIGHLY_RANKED_THIS_MONTH,
  POPULAR_IN_TOP_GENRE,
  MUTUALS_READING_NOW,
] as const;

// ---------------------------------------------------------------------------
// Registry helpers
// ---------------------------------------------------------------------------

/**
 * Look up a query definition by its type.
 * Returns undefined if the type is not registered.
 */
export function findQueryDefinition(
  type: AlgorithmicQueryType,
): AlgorithmicQueryDefinition | undefined {
  return ALGORITHMIC_QUERY_REGISTRY.find((q) => q.type === type);
}

/**
 * Get all query definitions scoped to a specific scope type.
 */
export function getQueriesByScope(
  scope: "per_user" | "global",
): AlgorithmicQueryDefinition[] {
  return ALGORITHMIC_QUERY_REGISTRY.filter((q) => q.scope === scope);
}

/**
 * Validate that query params are within acceptable ranges.
 * Returns an array of error messages (empty = valid).
 */
export function validateQueryParams(params: QueryParams): string[] {
  const errors: string[] = [];

  if (params.windowDays !== undefined && params.windowDays < 0) {
    errors.push("windowDays must be non-negative");
  }
  if (params.maxItems !== undefined && (params.maxItems < 1 || params.maxItems > 100)) {
    errors.push("maxItems must be between 1 and 100");
  }
  if (params.minThreshold !== undefined && params.minThreshold < 0) {
    errors.push("minThreshold must be non-negative");
  }

  return errors;
}

/**
 * Merge user-provided params with the definition's defaults.
 */
export function resolveParams(
  definition: AlgorithmicQueryDefinition,
  overrides?: QueryParams,
): Required<QueryParams> {
  if (!overrides) return definition.defaultParams;

  return {
    userId: overrides.userId ?? definition.defaultParams.userId,
    windowDays: overrides.windowDays ?? definition.defaultParams.windowDays,
    maxItems: overrides.maxItems ?? definition.defaultParams.maxItems,
    minThreshold: overrides.minThreshold ?? definition.defaultParams.minThreshold,
  };
}
